712→function loadProgress(surveyId) {
713→  try {
714→    const raw = localStorage.getItem(`lgf_${surveyId}`);
715→    if (!raw) return null;
716→    const saved = JSON.parse(raw);
717→    if (Date.now() - saved.ts > STORAGE_TTL_MS) {
718→      localStorage.removeItem(`lgf_${surveyId}`);
719→      return null;
720→    }
721→    return saved;
722→  } catch { return null; }
723→}
