748→function sendBeacon(surveyId, step, answeredCount, totalQuestions) {
749→  const sessionId = getSessionId(surveyId);
750→  if (!sessionId) return;
751→  try {
752→    const body = JSON.stringify({ surveyId, sessionId, step, answeredCount, totalQuestions });
753→    if (navigator.sendBeacon) {
754→      navigator.sendBeacon("/api/surveys/beacon", new Blob([body], { type: "application/json" }));
755→    } else {
756→      fetch("/api/surveys/beacon", { method: "POST", body, headers: { "Content-Type": "application/json" }, keepalive: true }).catch(() => {});
757→    }
758→  } catch { /* ignore */ }
759→}
