                      color: "#059669", fontSize: 13, fontWeight: 600,
                      animation: "lgf-fi 0.2s ease both",
                    }}>
                      URLをコピーしました
                    </div>
                  )}
                  <div style={{ display: "flex", gap: 8, marginTop: 8, justifyContent: "center" }}>
