                      target="_blank" rel="noopener"
                      style={{ fontSize: 13, color: s.textDim, textDecoration: "underline" }}
                    >
                      X (Twitter)
                    </a>
                    <span style={{ color: s.textDim, fontSize: 13 }}>|</span>
                    <button
