            if (m.type === "bot") {
              const isPrev = showInput && m.qStep !== undefined && m.qStep === prevQStep;
              return <Bot key={m.id} text={m.text} canGoBack={isPrev} onGoBack={isPrev ? goBack : undefined} />;
