import { NextRequest, NextResponse } from "next/server"
import { createServerClient } from "@supabase/ssr"
import { getOrCreateUserByEmail, linkWixContactByEmail } from "@/lib/supabase"
import { getContactByEmail, getMemberByContactId } from "@/lib/wix"
import { notifySlack } from "@/lib/slack"

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url)
  const code = searchParams.get("code")
  const error = searchParams.get("error")
  const errorDescription = searchParams.get("error_description")
  const redirectTo = new URL("/dashboard", request.url)

  // Supabase がエラー付きでリダイレクトしてきた場合（OTP期限切れ等）
  if (error) {
    const msg = errorDescription || error
    return NextResponse.redirect(
      new URL(`/auth/error?error=${encodeURIComponent(msg)}`, request.url),
    )
  }

  if (code) {
    const response = NextResponse.redirect(redirectTo)

    const supabase = createServerClient(
      process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
      {
        cookies: {
          getAll() {
            return request.cookies.getAll()
          },
          setAll(cookiesToSet) {
            cookiesToSet.forEach(({ name, value, options }) =>
              response.cookies.set(name, value, options),
            )
          },
        },
      },
    )

    const { data, error } = await supabase.auth.exchangeCodeForSession(code)

    if (error) {
      console.error("[auth/callback] exchangeCodeForSession error:", error)
      return NextResponse.redirect(
        new URL(`/auth/error?error=${encodeURIComponent(error.message)}`, request.url),
      )
    }

    // メールで Wix Contact 自動リンク + unified_users UPSERT
    const email = data.user?.email
    let wixLinked = false
    if (email) {
      try {
        await getOrCreateUserByEmail(email, data.user?.user_metadata?.full_name ?? null)

        const contact = await getContactByEmail(email)
        if (contact?._id) {
          const member = await getMemberByContactId(contact._id)
          await linkWixContactByEmail(email, contact._id, member?._id ?? null)
          wixLinked = true
        }
      } catch (e) {
        console.error("[auth/callback] Wix link error:", e)
      }

      // Slack ログイン通知
      const now = new Date().toLocaleString("ja-JP", { timeZone: "Asia/Tokyo" })
      await notifySlack(
        `✅ ログイン: ${email}\nProvider: ${data.user?.app_metadata?.provider ?? "email"}\nTime: ${now}\nWix: ${wixLinked ? "連携済み" : "未連携"}`,
      )
    }

    return response
  }

  // code がない場合はエラー
  return NextResponse.redirect(
    new URL("/auth/error?error=NoCode", request.url),
  )
}

import { createServerClient } from "@supabase/ssr"
import { NextResponse, type NextRequest } from "next/server"

export async function middleware(request: NextRequest) {
  let response = NextResponse.next({
    request: { headers: request.headers },
  })

  const supabase = createServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return request.cookies.getAll()
        },
        setAll(cookiesToSet) {
          cookiesToSet.forEach(({ name, value }) =>
            request.cookies.set(name, value),
          )
          response = NextResponse.next({
            request: { headers: request.headers },
          })
          cookiesToSet.forEach(({ name, value, options }) =>
            response.cookies.set(name, value, options),
          )
        },
      },
    },
  )

  const { data: { user } } = await supabase.auth.getUser()

  // Protect /dashboard/* pages — redirect to login
  if (!user && request.nextUrl.pathname.startsWith("/dashboard")) {
    return NextResponse.redirect(new URL("/", request.url))
  }

  // Protect /api/admin/* — return 401 JSON
  if (!user && request.nextUrl.pathname.startsWith("/api/admin")) {
    return NextResponse.json({ error: "unauthorized" }, { status: 401 })
  }

  return response
}

export const config = {
  matcher: ["/dashboard/:path*", "/api/admin/:path*"],
}

import { createClient, SupabaseClient } from "@supabase/supabase-js"
import { createServerClient as createSSRServerClient } from "@supabase/ssr"
import { cookies } from "next/headers"

// ─── 1. ブラウザ用 → src/lib/supabase-browser.ts に分離 ───

// ─── 2. サーバー用 (anon key + cookies, Server Component / Route Handler 用) ───
export async function createServerSupabase() {
  const cookieStore = await cookies()
  return createSSRServerClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll()
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) =>
              cookieStore.set(name, value, options),
            )
          } catch {
            // Server Component からの呼び出しでは set できない場合がある
          }
        },
      },
    },
  )
}

// ─── 3. 管理用 (service key, バックエンド処理用) ───
let _adminSupabase: SupabaseClient | null = null

export function getAdminSupabase() {
  if (!_adminSupabase) {
    _adminSupabase = createClient(
      process.env.SUPABASE_URL ?? process.env.NEXT_PUBLIC_SUPABASE_URL!,
      process.env.SUPABASE_SERVICE_KEY!,
    )
  }
  return _adminSupabase
}

// ─── Types ───
export type UnifiedUser = {
  id: string
  discord_id: string | null
  discord_email: string | null
  discord_username: string | null
  wix_contact_id: string | null
  wix_member_id: string | null
  stripe_customer_id: string | null
  chatwoot_contact_id: number | null
  primary_email: string | null
  display_name: string | null
  created_at: string
  updated_at: string
  last_login_at: string | null
}

// ─── User CRUD (admin client) ───

/** メールアドレスで unified_users を UPSERT（なければ作成） */
export async function getOrCreateUserByEmail(
  email: string,
  name: string | null,
) {
  const { data, error } = await getAdminSupabase()
    .from("unified_users")
    .upsert(
      {
        primary_email: email,
        display_name: name,
        last_login_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      },
      { onConflict: "primary_email" },
    )
    .select()
    .single()

  if (error) throw error
  return data as UnifiedUser
}

/** Discord ログイン時に unified_users を UPSERT（なければ作成） */
export async function getOrCreateUser(
  discordId: string,
  email: string | null,
  name: string | null,
) {
  const { data, error } = await getAdminSupabase()
    .from("unified_users")
    .upsert(
      {
        discord_id: discordId,
        discord_email: email,
        discord_username: name,
        primary_email: email,
        display_name: name,
        last_login_at: new Date().toISOString(),
        updated_at: new Date().toISOString(),
      },
      { onConflict: "discord_id" },
    )
    .select()
    .single()

  if (error) throw error
  return data as UnifiedUser
}

/** メールアドレスから unified_user を取得 */
export async function getUserByEmail(email: string) {
  const { data, error } = await getAdminSupabase()
    .from("unified_users")
    .select()
    .eq("primary_email", email)
    .single()

  if (error && error.code !== "PGRST116") throw error
  return (data as UnifiedUser) ?? null
}

/** Wix の contactId / memberId をメールアドレスベースで紐付け */
export async function linkWixContactByEmail(
  email: string,
  wixContactId: string,
  wixMemberId: string | null,
) {
  const { data, error } = await getAdminSupabase()
    .from("unified_users")
    .update({
      wix_contact_id: wixContactId,
      wix_member_id: wixMemberId,
      updated_at: new Date().toISOString(),
    })
    .eq("primary_email", email)
    .select()
    .single()

  if (error) throw error
  return data as UnifiedUser
}

/** Wix の contactId / memberId を unified_users に紐付け（Discord ID ベース） */
export async function linkWixContact(
  discordId: string,
  wixContactId: string,
  wixMemberId: string | null,
) {
  const { data, error } = await getAdminSupabase()
    .from("unified_users")
    .update({
      wix_contact_id: wixContactId,
      wix_member_id: wixMemberId,
      updated_at: new Date().toISOString(),
    })
    .eq("discord_id", discordId)
    .select()
    .single()

  if (error) throw error
  return data as UnifiedUser
}

// ─── Survey responses ───

export type SurveyResponse = {
  id: string
  survey_id: string
  submitted_at: string
  reward_status: string
}

/** メールアドレスからアンケート回答履歴を取得 */
export async function getSurveyResponsesByEmail(email: string): Promise<SurveyResponse[]> {
  const { data, error } = await getAdminSupabase()
    .from("survey_responses")
    .select("id, survey_id, submitted_at, reward_status")
    .eq("email", email)
    .order("submitted_at", { ascending: false })
    .limit(20)

  if (error) { console.error("getSurveyResponsesByEmail:", error); return [] }
  return (data ?? []) as SurveyResponse[]
}

/** Discord ID から unified_user を取得 */
export async function getUserByDiscordId(discordId: string) {
  const { data, error } = await getAdminSupabase()
    .from("unified_users")
    .select()
    .eq("discord_id", discordId)
    .single()

  if (error && error.code !== "PGRST116") throw error
  return (data as UnifiedUser) ?? null
}

/** Chatwoot Contact ID を紐付け（メールアドレス or Supabase Auth UID、なければ新規作成） */
export async function linkChatwootContact(
  identifier: string,
  chatwootContactId: number,
  email?: string,
  name?: string,
) {
  const supabase = getAdminSupabase()
  const updateData = {
    chatwoot_contact_id: chatwootContactId,
    updated_at: new Date().toISOString(),
  }

  // まずメールアドレスで検索（より確実）
  if (email) {
    const { data, error } = await supabase
      .from("unified_users")
      .update(updateData)
      .eq("primary_email", email)
      .select()
      .single()
    if (!error && data) return data as UnifiedUser
  }

  // フォールバック: identifier (Supabase Auth UID) で検索
  if (identifier) {
    const { data, error } = await supabase
      .from("unified_users")
      .update(updateData)
      .eq("id", identifier)
      .select()
      .single()
    if (!error && data) return data as UnifiedUser
  }

  // どちらにも一致しない → 新規作成
  const { data, error } = await supabase
    .from("unified_users")
    .insert({
      primary_email: email || null,
      display_name: name || null,
      chatwoot_contact_id: chatwootContactId,
      updated_at: new Date().toISOString(),
    })
    .select()
    .single()

  if (error) throw error
  return data as UnifiedUser
}

import { createBrowserClient } from "@supabase/ssr"

export function createBrowserSupabase() {
  return createBrowserClient(
    process.env.NEXT_PUBLIC_SUPABASE_URL!,
    process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!,
  )
}

