      )}

      <style>{`
        @keyframes lgf-fi { from { opacity: 0; transform: translateY(10px); } to { opacity: 1; transform: translateY(0); } }
        @keyframes lgf-tb { 0%,60%,100% { transform: translateY(0); } 30% { transform: translateY(-4px); } }
        .lgf-choice {
